"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[3796],{2191(e,t,s){s.r(t),s.d(t,{assets:()=>r,contentTitle:()=>h,default:()=>c,frontMatter:()=>a,metadata:()=>o,toc:()=>d});const o=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-28","title":"Discourses \u2014 Book 1, Chapter 28","description":"Book 1 \u2014 Chapter 28","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-28.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-28","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-28","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":28,"frontMatter":{"sidebar_position":28,"title":"Discourses \u2014 Book 1, Chapter 28","sidebar_label":"Book 1, Ch. 28"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 27","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-27"},"next":{"title":"Book 1, Ch. 29","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-29"}}');var n=s(4848),i=s(8453);const a={sidebar_position:28,title:"Discourses \u2014 Book 1, Chapter 28",sidebar_label:"Book 1, Ch. 28"},h="Discourses",r={},d=[{value:"Book 1 \u2014 Chapter 28",id:"book-1--chapter-28",level:2},{value:"That We Must Not Be Angry With Men: And Concerning What Things Are Small And What Are Great Among Men",id:"that-we-must-not-be-angry-with-men-and-concerning-what-things-are-small-and-what-are-great-among-men",level:3},{value:"Text",id:"text",level:2}];function l(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:s}=t;return s||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,n.jsxs)(n.Fragment,{children:[(0,n.jsxs)("div",{style:{textAlign:"center"},children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,n.jsx)(t.h2,{id:"book-1--chapter-28",children:"Book 1 \u2014 Chapter 28"}),(0,n.jsx)(t.h3,{id:"that-we-must-not-be-angry-with-men-and-concerning-what-things-are-small-and-what-are-great-among-men",children:"That We Must Not Be Angry With Men: And Concerning What Things Are Small And What Are Great Among Men"})]}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,n.jsxs)(s,{open:!0,children:[(0,n.jsx)("summary",{children:"Text"}),(0,n.jsx)(t.h2,{id:"text",children:"Text"}),(0,n.jsx)(t.p,{children:"WHAT is the reason that we assent to a thing? Because it seems to us that it is so. It is impossible that we shall assent to that which seems not to be. Why? Because this is the nature of the mind--to agree to what is true, and disagree with what is false, and withhold judgement on what is doubtful."}),(0,n.jsx)(t.p,{children:"What is the proof of this?"}),(0,n.jsx)(t.p,{children:"'Feel now, if you can, that it is night.'"}),(0,n.jsx)(t.p,{children:"It is impossible."}),(0,n.jsx)(t.p,{children:"Put away the feeling that it is day.'"}),(0,n.jsx)(t.p,{children:"It is impossible."}),(0,n.jsx)(t.p,{children:"'Assume or put away the feeling that the stars are even in number.' It is not possible."}),(0,n.jsx)(t.p,{children:"When a man assents, then, to what is false, know that he had no wish to assent to the false: 'for no soul is robbed of the truth with its own consent,' as Plato says, but the false seemed to him true."}),(0,n.jsx)(t.p,{children:"Now, in the sphere of action what have we to correspond to true and false in the sphere of perception? What is fitting and unfitting, profitable and unprofitable, appropriate and inappropriate, and the like."}),(0,n.jsx)(t.p,{children:"Cannot a man, then, think a thing is to his profit, and not choose it?"}),(0,n.jsx)(t.p,{children:"He cannot."}),(0,n.jsx)(t.p,{children:"What of her  who says"}),(0,n.jsx)(t.p,{children:"I know full well what ills I mean to do"}),(0,n.jsx)(t.p,{children:"But passion overpowers what counsel bids me."}),(0,n.jsx)(t.p,{children:"[Euripides, Medea, 1078]"}),(0,n.jsx)(t.p,{children:"Here the very gratification of passion and the vengeance she takes on"}),(0,n.jsx)(t.p,{children:"her husband she believes to be more to her profit than saving her children."}),(0,n.jsx)(t.p,{children:"'Yes, but she is deceived.'"}),(0,n.jsx)(t.p,{children:"Prove to her plainly that she is deceived and she will not do it, but as long as you do not show her, what else can she follow but that which appears to her? Nothing. Why then are you indignant with her, because, unhappy woman, she is deluded on the greatest matters and is transformed from a human being into a serpent? Why do you not rather pity her--if so it may be? As we pity the blind and the lame, so should we pity those who are blinded and lamed in their most sovereign faculties."}),(0,n.jsx)(t.p,{children:"We must remember this clearly, that man measures his every action by his impressions; of course they may be good or bad: if good, he is free from reproach; if bad, he pays the penalty in his own person, for it is impossible for one to be deluded and another to suffer for it. The man who remembers this, I say, will be angry with no one, indignant with no one, revile none, blame none, hate none, offend none."}),(0,n.jsx)(t.p,{children:"'So you say that deeds so great and awful take their origin from this, the impressions of the mind?'"}),(0,n.jsx)(t.p,{children:"From this and nothing else. The Iliad is nothing but men's impressions and how they dealt with them. It was impressions that made Paris take away the wife of Menelaus, impressions that drew Helen to follow him. If, then, his impressions had led Menelaus to feel that it was a gain to be robbed of such a wife, what would have happened? We should have lost the Iliad, and not only that but the Odyssey too."}),(0,n.jsx)(t.p,{children:"'What? Do these great matters depend on one that is so small?'"}),(0,n.jsx)(t.p,{children:"What are these you call 'such great matters'? Wars and factions, deaths of many men and destructions of cities. What is there great in this, pray?"}),(0,n.jsx)(t.p,{children:"'Is there nothing great?'"}),(0,n.jsx)(t.p,{children:"Why, what is there great in the death of many oxen and many sheep, and the burning and destruction of many nests of swallows and storks? 'Are these like those other horrors?'"}),(0,n.jsx)(t.p,{children:"Most like: bodies of men perished, so did bodies of oxen and sheep. Huts of men were burnt: so were storks' nests. What is great or awful here? Or if it be so, show me how a man's home differs from a stork's nest, as a dwelling."}),(0,n.jsx)(t.p,{children:"'Is a stork, then, like a man?'"}),(0,n.jsx)(t.p,{children:"What do you say? In respect of his body, very like; save only that men's homes are built of beams and rafters and bricks, and storks' nests of sticks and clay."}),(0,n.jsx)(t.p,{children:"'Does a man then differ in nothing from a stork?'"}),(0,n.jsx)(t.p,{children:"God forbid: but he does not differ in these matters."}),(0,n.jsx)(t.p,{children:"'In what then does he differ?'"}),(0,n.jsx)(t.p,{children:"Search and you will find that he differs in something else. Look whether it be not that he differs in understanding what he does, in his faculty for society, in his good faith, his self-respect, his security of aim, his prudence."}),(0,n.jsx)(t.p,{children:"Where then is man's good and man's evil, in the true sense, to be found?"}),(0,n.jsx)(t.p,{children:"In that faculty which makes men different from all else. If a man preserves this and keeps it safely fortified; if his sense of honour, his good faith, and his prudence are not destroyed, then he too is preserved; but if any of these perish or be taken by storm, then he too perishes with them. And it is on this that great events depend. Was Alexander's great failure when the Hellenes came against the Trojans and sacked Troy and when his brothers perished? By no means: for no one fails by the act of another; yet then there was destruction of storks' nests. Nay, his failure was when he lost the man of honour, the man of good faith, the man who respected manners and the laws of hospitality. When did Achilles fail? Was it when Patroclus died? God forbid: it was when he was angry, when he cried for a trumpery maiden, when he forgot that he was there not to win lady-loves, but to make war. These are man's failures--this is his siege, this is his razed city, when his right judgements are broken to the ground, and when they are destroyed."}),(0,n.jsx)(t.p,{children:"'But when women are carried off, and children are made captive, and men themselves are slaughtered--are not these things evil?'"}),(0,n.jsx)(t.p,{children:"Where do you get this idea from? If it is true, teach it me too."}),(0,n.jsx)(t.p,{children:"'No, I cannot: but how can you say that they are not evil?'"}),(0,n.jsx)(t.p,{children:"Let us turn to our standards, let us look to our primary notions. For I cannot be sufficiently astonished at what men do. When we want to judge weights, we do not judge at random: when we judge things straight and crooked, it is not at random: in a word, when it is important to us to know the truth on any subject, no one of us will ever do anything at random. Yet when we are dealing with the primary and sole cause of right or wrong action, of prosperity or adversity, of good or bad fortune, there alone we are random and headlong: we nowhere have anything like a scale, nowhere anything like a standard: some impression strikes me, and straightway I act on it."}),(0,n.jsx)(t.p,{children:"Am I any better than Agamemnon or Achilles, that they should do and suffer such evils because they follow their impressions, and I should be content with mine?"}),(0,n.jsx)(t.p,{children:"Surely tragedy has no other source but this. What is the 'Atreus' of Euripides? Impressions. What is the 'Oedipus' of Sophocles? Impressions. 'Phoenix'? Impressions. 'Hippolytus'? Impressions. How do you think then we should describe the man who takes no pains to discipline"}),(0,n.jsx)(t.p,{children:"his impressions? What name do we give to those who follow everything that comes into their mind?"}),(0,n.jsx)(t.p,{children:"'Madmen.'"}),(0,n.jsx)(t.p,{children:"Well, is not this exactly what we do?"})]})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(l,{...e})}):l(e)}},8453(e,t,s){s.d(t,{R:()=>a,x:()=>h});var o=s(6540);const n={},i=o.createContext(n);function a(e){const t=o.useContext(i);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function h(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:a(e.components),o.createElement(i.Provider,{value:t},e.children)}}}]);